#include <iostream>
#include <deque>

using namespace std;

class Solution {
public:
    void push(deque<int>& q, int val) { q.push_back(val); }
    int pop(deque<int>& q) {
        if (q.empty()) return -1;
        int val = q.front();
        q.pop_front();
        return val;
    }
    int isEmpty(const deque<int>& q) {
        return q.empty();
    }
};

testCase() {
    Solution solution;
    deque<int> q;
    solution.push(q, 2);
    cout << solution.pop(q) << endl;  // Output: 2
    cout << solution.pop(q) << endl;  // Output: -1
    cout << solution.isEmpty(q) << endl;  // Output: 1
}

